/**
 * @swagger
 *   components:
 *    securitySchemes:
 *     bearerAuth:
 *      type: http
 *      scheme: bearer
 *      bearerFormat: JWT
 *    schemas:
 *      AuthenticationResponse:
 *          type: object
 *          properties:
 *            message:
 *              type: string
 *              description: Authentication response.
 *            token:
 *              type: string
 *              description: JWT access token.
 *            email:
 *              type: string
 *              description: User email.
 *            firstName:
 *              type: string
 *              description: User first name.
 *            lastName:
 *              type: string
 *              description: User last name.
 *      AuthenticationRequest:
 *          type: object
 *          properties:
 *            email:
 *              type: string
 *              description: User email.
 *            password:
 *              type: string
 *              description: User password.
 *      User:
 *          type: object
 *          properties:
 *            id:
 *              type: number
 *              format: int64
 *            email:
 *              type: string
 *              description: User email.
 *            firstName:
 *              type: string
 *              description: User first name.
 *            lastName:
 *              type: string
 *              description: User last name.
 *            isOrganiser:
 *              type: boolean
 *              description: Whether the user is an organiser.
 *            createdAt:
 *              type: string
 *              format: date-time
 *              description: User creation date.
 *            updatedAt:
 *              type: string
 *              format: date-time
 *              description: User last update date.
 *      UserInput:
 *          type: object
 *          properties:
 *            email:
 *              type: string
 *              description: User email.
 *            password:
 *              type: string
 *              description: User password.
 *            firstName:
 *              type: string
 *              description: User first name.
 *            lastName:
 *              type: string
 *              description: User last name.
 *            isOrganiser:
 *              type: boolean
 *              description: Whether the user is an organiser.
 *              default: false
 */
import express, { NextFunction, Request, Response } from 'express';
import rateLimit from 'express-rate-limit';
import userService from '../service/user.service';
import { UserInput } from '../types/index';
import { logger, logSecurityEvent } from '../util/logger';

const userRouter = express.Router();

// In-memory token blacklist (in production, use Redis or database)
const tokenBlacklist = new Set<string>();

// Rate limiting for login endpoint - 5 attempts per 15 minutes
const loginLimiter = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 5, // 5 attempts per IP
    message: 'Too many login attempts, please try again later',
    standardHeaders: true,
    legacyHeaders: false,
});

// Rate limiting for signup - 10 attempts per hour
const signupLimiter = rateLimit({
    windowMs: 60 * 60 * 1000, // 1 hour
    max: 10, // 10 attempts per IP
    message: 'Too many signup attempts, please try again later',
    standardHeaders: true,
    legacyHeaders: false,
});

// Rate limiting for password reset - 5 attempts per hour
const passwordResetLimiter = rateLimit({
    windowMs: 60 * 60 * 1000, // 1 hour
    max: 5, // 5 attempts per IP
    message: 'Too many password reset attempts, please try again later',
    standardHeaders: true,
    legacyHeaders: false,
});

// Rate limiting for email verification - 10 attempts per hour
const verificationLimiter = rateLimit({
    windowMs: 60 * 60 * 1000, // 1 hour
    max: 10, // 10 attempts per IP
    message: 'Too many verification attempts, please try again later',
    standardHeaders: true,
    legacyHeaders: false,
});

// Rate limiting for MFA verification - 5 attempts per 10 minutes
const mfaLimiter = rateLimit({
    windowMs: 10 * 60 * 1000, // 10 minutes
    max: 5, // 5 attempts per IP
    message: 'Too many MFA verification attempts, please try again later',
    standardHeaders: true,
    legacyHeaders: false,
});

/**
 * @swagger
 * /users/signup:
 *   post:
 *      summary: Register a new user with email verification required
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                firstName:
 *                  type: string
 *                lastName:
 *                  type: string
 *                email:
 *                  type: string
 *                password:
 *                  type: string
 *                isOrganiser:
 *                  type: boolean
 *      responses:
 *         201:
 *            description: User registered successfully
 *         400:
 *            description: Invalid request data
 */
userRouter.post('/signup', signupLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        logger.info('📝 Signup request received');
        const { firstName, lastName, email, password, isOrganiser } = req.body;
        logger.info({ email }, '🔄 Processing signup...');
        const response = await userService.signup({
            firstName,
            lastName,
            email,
            password,
            isOrganiser: isOrganiser ?? false,
        });
        logger.info({ email }, '✅ Signup successful');
        res.status(201).json(response);
    } catch (error) {
        logger.error({ error: error instanceof Error ? error.message : 'Unknown error' }, '❌ Signup error');
        next(error);
    }
});

/**
 * @swagger
 * /users/verify-email:
 *   post:
 *      summary: Verify user email with verification token
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                token:
 *                  type: string
 *      responses:
 *         200:
 *            description: Email verified successfully
 *         400:
 *            description: Invalid or expired token
 */
userRouter.post('/verify-email', verificationLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        const { token } = req.body;
        const response = await userService.verifyEmail({ token });
        res.status(200).json(response);
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/resend-verification:
 *   post:
 *      summary: Resend verification email
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                email:
 *                  type: string
 *      responses:
 *         200:
 *            description: Verification email resent
 *         400:
 *            description: Invalid email or already verified
 */
userRouter.post('/resend-verification', verificationLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        const { email } = req.body;
        const response = await userService.resendVerificationEmail({ email });
        res.status(200).json(response);
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/login:
 *   post:
 *      summary: Login using email/password. Returns an object with JWT token and user details when successful.
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              $ref: '#/components/schemas/AuthenticationRequest'
 *      responses:
 *         200:
 *            description: Authentication successful
 *            content:
 *              application/json:
 *                schema:
 *                  $ref: '#/components/schemas/AuthenticationResponse'
 *         400:
 *            description: Invalid credentials or request data
 *            content:
 *              application/json:
 *                schema:
 *                  type: object
 *                  properties:
 *                    status:
 *                      type: string
 *                      example: "application error"
 *                    message:
 *                      type: string
 *                      example: "Incorrect password."
 */
userRouter.post('/login', loginLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        const userInput = <UserInput>req.body;
        const response = await userService.authenticate(userInput);
        res.status(200).json({ message: 'Authentication successful', ...response });
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/verify-mfa:
 *   post:
 *      summary: Verify MFA code sent via email
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                userId:
 *                  type: number
 *                mfaCode:
 *                  type: string
 *      responses:
 *         200:
 *            description: MFA verified successfully
 *         400:
 *            description: Invalid or expired MFA code
 */
userRouter.post('/verify-mfa', mfaLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        const { userId, mfaCode } = req.body;
        const response = await userService.verifyMFA({ userId, mfaCode });
        res.status(200).json({ message: 'MFA verified successfully', ...response });
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/forgot-password:
 *   post:
 *      summary: Initiate password reset process
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                email:
 *                  type: string
 *      responses:
 *         200:
 *            description: Password reset email sent
 *         400:
 *            description: Invalid request
 */
userRouter.post('/forgot-password', passwordResetLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        const { email } = req.body;
        const response = await userService.forgotPassword({ email });
        res.status(200).json(response);
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/reset-password:
 *   post:
 *      summary: Reset password with valid reset token
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                token:
 *                  type: string
 *                newPassword:
 *                  type: string
 *      responses:
 *         200:
 *            description: Password reset successfully
 *         400:
 *            description: Invalid or expired token
 */
userRouter.post('/reset-password', passwordResetLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        const { token, newPassword } = req.body;
        const response = await userService.resetPassword({ token, newPassword });
        res.status(200).json(response);
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/change-password:
 *   post:
 *      summary: Change password while logged in (initiates MFA)
 *      tags:
 *        - Authentication
 *      security:
 *        - bearerAuth: []
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                currentPassword:
 *                  type: string
 *                newPassword:
 *                  type: string
 *      responses:
 *         200:
 *            description: MFA code sent to email
 *         400:
 *            description: Invalid current password
 *         401:
 *            description: Unauthorized
 */
userRouter.post('/change-password', async (req: Request, res: Response, next: NextFunction) => {
    try {
        const userId = (req as any).auth?.userId;
        if (!userId) {
            return res.status(401).json({ message: 'Unauthorized' });
        }

        const { currentPassword, newPassword } = req.body;
        const response = await userService.changePassword({
            userId,
            currentPassword,
            newPassword,
        });
        res.status(200).json(response);
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/verify-change-password:
 *   post:
 *      summary: Verify MFA and complete password change
 *      tags:
 *        - Authentication
 *      security:
 *        - bearerAuth: []
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                mfaCode:
 *                  type: string
 *                newPassword:
 *                  type: string
 *      responses:
 *         200:
 *            description: Password changed successfully
 *         400:
 *            description: Invalid MFA code
 *         401:
 *            description: Unauthorized
 */
userRouter.post('/verify-change-password', mfaLimiter, async (req: Request, res: Response, next: NextFunction) => {
    try {
        const userId = (req as any).auth?.userId;
        if (!userId) {
            return res.status(401).json({ message: 'Unauthorized' });
        }

        const { mfaCode, newPassword } = req.body;
        const response = await userService.verifyChangePassword({
            userId,
            mfaCode,
            newPassword,
        });
        res.status(200).json(response);
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/remember-me:
 *   post:
 *      summary: Create remember me token for persistent login
 *      tags:
 *        - Authentication
 *      security:
 *        - bearerAuth: []
 *      responses:
 *         200:
 *            description: Remember me token created
 *         401:
 *            description: Unauthorized
 */
userRouter.post('/remember-me', async (req: Request, res: Response, next: NextFunction) => {
    try {
        const userId = (req as any).auth?.userId;
        if (!userId) {
            return res.status(401).json({ message: 'Unauthorized' });
        }

        const response = await userService.createRememberMeToken({ userId });
        res.status(200).json(response);
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/login-with-token:
 *   post:
 *      summary: Login using remember me token
 *      tags:
 *        - Authentication
 *      requestBody:
 *        required: true
 *        content:
 *          application/json:
 *            schema:
 *              type: object
 *              properties:
 *                rememberMeToken:
 *                  type: string
 *      responses:
 *         200:
 *            description: Login successful
 *         400:
 *            description: Invalid or expired token
 */
userRouter.post('/login-with-token', async (req: Request, res: Response, next: NextFunction) => {
    try {
        const { rememberMeToken } = req.body;
        const response = await userService.verifyRememberMeToken({ token: rememberMeToken });
        res.status(200).json({ message: 'Login successful', ...response });
    } catch (error) {
        next(error);
    }
});

/**
 * @swagger
 * /users/logout:
 *   post:
 *      summary: Logout the current user. Invalidates the JWT token and revokes remember me tokens.
 *      tags:
 *        - Authentication
 *      security:
 *        - bearerAuth: []
 *      responses:
 *         200:
 *            description: Logout successful
 *         401:
 *            description: Unauthorized
 */
userRouter.post('/logout', async (req: Request, res: Response, next: NextFunction) => {
    try {
        const token = req.headers.authorization?.split(' ')[1];
        const userId = (req as any).auth?.userId;

        if (token) {
            tokenBlacklist.add(token);
        }

        if (userId) {
            await userService.logout({ userId });
            logSecurityEvent('LOGOUT', {
                userId,
            });
            logger.info({ userId }, '👋 User logged out');
        }

        res.status(200).json({ message: 'Logged out successfully' });
    } catch (error) {
        next(error);
    }
});

export { userRouter, tokenBlacklist };

import eventDB from '../repository/event.db';
import userDB from '../repository/user.db';
import { Event } from '../model/event';
import { User } from '../model/user';

const getAllEvents = async (): Promise<Event[]> => {
    return eventDB.getAllEvents();
};

const getEventById = async ({ id }: { id: number }): Promise<Event> => {
    const event = await eventDB.getEventById({ id });
    if (!event) {
        throw new Error(`Event with id: ${id} does not exist.`);
    }
    return event;
};

const getEventsByOrganiserId = async ({ organiserId }: { organiserId: number }): Promise<Event[]> => {
    return eventDB.getEventsByOrganiserId({ organiserId });
};

const getUpcomingEvents = async (): Promise<Event[]> => {
    const allEvents = await eventDB.getAllEvents();
    const now = new Date();
    return allEvents.filter((event) => event.getDate() > now);
};

const createEvent = async ({
    name,
    description,
    date,
    location,
    organiserId,
}: {
    name: string;
    description: string;
    date: Date;
    location: string;
    organiserId: number;
}): Promise<Event> => {
    // Check organiser
    const organiser = await userDB.getUserById({ id: organiserId });
    if (!organiser) throw new Error('Organiser not found');
    if (!organiser.getIsOrganiser()) throw new Error('Only organisers can create experiences');
    // Validate date
    const eventDate = new Date(date);
    if (eventDate <= new Date()) throw new Error('Experience date must be in the future');

    // Check for existing event on the same day for this organiser
    const existingEvents = await eventDB.getEventsByOrganiserId({ organiserId });
    const sameDayEvent = existingEvents.find(ev => {
        const evDate = new Date(ev.getDate());
        return (
            evDate.getFullYear() === eventDate.getFullYear() &&
            evDate.getMonth() === eventDate.getMonth() &&
            evDate.getDate() === eventDate.getDate()
        );
    });
    if (sameDayEvent) {
        throw new Error('You already have an experience on this day.');
    }

    return eventDB.createEvent({
        name,
        description,
        date: eventDate,
        location,
        organiserId,
    });
};

export default {
    getAllEvents,
    getEventById,
    getEventsByOrganiserId,
    getUpcomingEvents,
    createEvent,
};

import tripDB from '../repository/trip.db';
import userDB from '../repository/user.db';
import { Trip } from '../model/trip';
import { User } from '../model/user';

const getAllTrips = async (): Promise<Trip[]> => tripDB.getAllTrips();

const getTripById = async ({ id }: { id: number }): Promise<Trip> => {
    const trip = await tripDB.getTripById({ id });
    if (!trip) {
        throw new Error(`Trip with id: ${id} does not exist.`);
    }
    return trip;
};

const getUpcomingTrips = async (): Promise<Trip[]> => {
    const allTrips = await tripDB.getAllTrips();
    const now = new Date();
    return allTrips.filter((trip) => trip.getStartDate() > now);
};

export default {
    getAllTrips,
    getTripById,
    getUpcomingTrips,
};

import bcrypt from 'bcrypt';
import userDB from '../repository/user.db';
import { AuthenticationResponse, UserInput } from '../types';
import { generateJwtToken } from '../util/jwt';
import { User } from '../model/user';
import { logger, logSecurityEvent } from '../util/logger';
import emailService from '../util/email.service';
import passwordValidator from '../util/password.validator';
import tokenGenerator from '../util/token.generator';

const getUserByEmail = async ({ email }: { email: string }): Promise<User> => {
    const user = await userDB.getUserByEmail({ email });
    if (!user) {
        logger.warn({ email }, '❌ Login attempt for non-existent user');
        throw new Error(`User with email: ${email} does not exist.`);
    }
    return user;
};

const getUserById = async ({ id }: { id: number }): Promise<User> => {
    const user = await userDB.getUserById({ id });
    if (!user) {
        logger.warn({ userId: id }, '⚠️ User not found by ID');
        throw new Error(`User with id: ${id} does not exist.`);
    }
    return user;
};

/**
 * SIGNUP - Register a new user with email verification
 * Threat mitigated: Prevents unauthorized account creation, ensures valid emails
 */
const signup = async ({
    firstName,
    lastName,
    email,
    password,
    isOrganiser,
}: {
    firstName: string;
    lastName: string;
    email: string;
    password: string;
    isOrganiser: boolean;
}): Promise<{ message: string }> => {
    try {
        // Check if user already exists
        const existingUser = await userDB.getUserByEmail({ email });
        if (existingUser) {
            logSecurityEvent('SIGNUP_FAILED', {
                email,
                reason: 'Email already registered',
            });
            throw new Error('Email already registered. Please use a different email or try logging in.');
        }

        // Validate password policy
        const passwordValidation = passwordValidator.validate(password);
        if (!passwordValidation.isValid) {
            throw new Error(passwordValidation.errors.join('. '));
        }

        // Check if password contains email
        if (passwordValidator.isPasswordContainsEmail(password, email)) {
            throw new Error('Password must not contain your email address');
        }

        // Create email verification token (valid for 24 hours)
        const verificationToken = tokenGenerator.generateSecureToken();
        const verificationTokenExp = tokenGenerator.getExpirationTime(24 * 60); // 24 hours

        // Create user in database
        const user = await userDB.createUser({
            firstName,
            lastName,
            email,
            password,
            isOrganiser,
            emailVerificationToken: verificationToken,
            emailVerificationTokenExp: verificationTokenExp,
        });

        // Send verification email (non-blocking - fire and forget)
        emailService.sendVerificationEmail(email, verificationToken, firstName)
            .catch((err: any) => {
                logger.error({ email, error: err instanceof Error ? err.message : 'Unknown error' }, '📧 Failed to send verification email');
                // Email failure is not critical - user can still verify later or request resend
            });

        logSecurityEvent('SIGNUP', {
            email,
            role: isOrganiser ? 'ORGANISER' : 'CLIENT',
        });

        return {
            message: 'Account created successfully! Please check your email to verify your account.',
        };
    } catch (error) {
        logger.error({ email, error: error instanceof Error ? error.message : 'Unknown error' }, '🔐 Signup error');
        throw error;
    }
};

/**
 * VERIFY EMAIL - Confirm email ownership
 * Threat mitigated: Ensures email ownership, prevents spam, enables communication with user
 */
const verifyEmail = async ({ token }: { token: string }): Promise<{ message: string }> => {
    try {
        const user = await userDB.getUserByVerificationToken({ token });
        if (!user) {
            logSecurityEvent('EMAIL_VERIFICATION_FAILED', {
                reason: 'Invalid token',
            });
            throw new Error('Invalid or expired verification token.');
        }

        // Check if token has expired
        if (tokenGenerator.isTokenExpired(user.getEmailVerificationTokenExp())) {
            logSecurityEvent('EMAIL_VERIFICATION_FAILED', {
                userId: user.getId(),
                reason: 'Token expired',
            });
            throw new Error('Verification token has expired. Please request a new one.');
        }

        // Verify email
        const updatedUser = await userDB.verifyEmail({ id: user.getId()! });

        logSecurityEvent('EMAIL_VERIFIED', {
            userId: user.getId(),
            email: user.getEmail(),
        });

        return {
            message: 'Email verified successfully! You can now log in.',
        };
    } catch (error) {
        logger.error({ error: error instanceof Error ? error.message : 'Unknown error' }, '🔐 Email verification error');
        throw error;
    }
};

/**
 * Resend verification email
 */
const resendVerificationEmail = async ({ email }: { email: string }): Promise<{ message: string }> => {
    try {
        const user = await getUserByEmail({ email });

        if (user.getEmailVerified()) {
            throw new Error('Email is already verified.');
        }

        // Generate new verification token
        const verificationToken = tokenGenerator.generateSecureToken();
        const verificationTokenExp = tokenGenerator.getExpirationTime(24 * 60); // 24 hours

        // Update user with new token
        await userDB.updateEmailVerificationToken({
            id: user.getId()!,
            token: verificationToken,
            expiresAt: verificationTokenExp,
        });

        // Send new verification email (non-blocking - fire and forget)
        emailService.sendVerificationEmail(email, verificationToken, user.getFirstName())
            .catch((err: any) => {
                logger.error({ email, error: err instanceof Error ? err.message : 'Unknown error' }, '📧 Failed to send verification email');
            });

        logSecurityEvent('VERIFICATION_EMAIL_RESENT', {
            email,
        });

        return {
            message: 'Verification email sent. Please check your inbox.',
        };
    } catch (error) {
        logger.error({ email, error: error instanceof Error ? error.message : 'Unknown error' }, '🔐 Resend verification error');
        throw error;
    }
};

/**
 * AUTHENTICATE - Login with email and password
 * Threat mitigated: Failed login tracking, account lockout after multiple attempts, MFA
 */
const authenticate = async ({ email, password }: UserInput): Promise<AuthenticationResponse> => {
    try {
        const user = await getUserByEmail({ email });

        // Check if email is verified
        if (!user.getEmailVerified()) {
            logSecurityEvent('LOGIN_FAILED', {
                email,
                reason: 'Email not verified',
            });
            throw new Error('Please verify your email before logging in. Check your inbox for the verification link.');
        }

        // Check if account is locked
        if (user.isAccountLocked()) {
            logSecurityEvent('LOGIN_FAILED', {
                userId: user.getId(),
                email,
                reason: 'Account locked',
            });
            const minutesLeft = Math.ceil((user.getLockedUntil()!.getTime() - new Date().getTime()) / (1000 * 60));
            throw new Error(`Account is locked due to too many failed login attempts. Try again in ${minutesLeft} minutes.`);
        }

        const isValidPassword = await bcrypt.compare(password, user.getPassword());

        if (!isValidPassword) {
            // Increment failed login attempts
            const newAttempts = user.getFailedLoginAttempts() + 1;
            const MAX_ATTEMPTS = 5;
            const LOCKOUT_DURATION_MINUTES = 30;

            let lockedUntil = null;
            if (newAttempts >= MAX_ATTEMPTS) {
                lockedUntil = new Date();
                lockedUntil.setMinutes(lockedUntil.getMinutes() + LOCKOUT_DURATION_MINUTES);
                
                logSecurityEvent('ACCOUNT_LOCKED', {
                    userId: user.getId(),
                    email,
                    reason: 'Max failed login attempts',
                });
            }

            await userDB.updateFailedLoginAttempts({
                id: user.getId()!,
                attempts: newAttempts,
                lockedUntil,
            });

            logSecurityEvent('FAILED_AUTH', {
                email,
                attempts: newAttempts,
                reason: 'Invalid password',
            });

            if (newAttempts >= MAX_ATTEMPTS) {
                throw new Error('Too many failed login attempts. Your account has been locked for 30 minutes.');
            }

            throw new Error('Incorrect password.');
        }

        // Reset failed login attempts on successful authentication
        await userDB.resetFailedLoginAttempts({ id: user.getId()! });

        // Check if MFA is enabled - if so, send MFA code
        if (user.getMfaEnabled()) {
            const mfaCode = tokenGenerator.generateMFACode();
            const mfaCodeExp = tokenGenerator.getExpirationTime(10); // 10 minutes

