            emailService.sendMFAEmail(user.getEmail(), mfaCode, user.getFirstName())
                .catch((err: any) => {
                    logger.error({ email: user.getEmail(), error: err instanceof Error ? err.message : 'Unknown error' }, '📧 Failed to send MFA email');
